import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer,
} from "recharts";
import axios from "axios";

interface Growth {
  date: string;
  score: number;
}

export default function PersonalGrowth() {
  const { username, platform } = useParams<{
    username: string;
    platform: string;
  }>();

  const [data, setData] = useState<Growth[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    if (!username || !platform) {
      setError("Missing username or platform");
      setLoading(false);
      return;
    }

    setLoading(true);
    setError("");

    axios
      .get(`http://localhost:5000/user/${platform}/${username}/history`)
      .then((res) => {
        setData(res.data || []);
        setLoading(false);
      })
      .catch(() => {
        setError("Unable to fetch user data. User may not exist yet.");
        setLoading(false);
      });
  }, [username, platform]);

  /* -------------------- LOADING STATE -------------------- */
  if (loading) {
    return (
      <div className="max-w-5xl mx-auto p-6 animate-pulse">
        <div className="h-6 w-48 bg-gray-300 dark:bg-gray-700 rounded mb-4" />
        <div className="h-64 bg-gray-300 dark:bg-gray-700 rounded-lg" />
      </div>
    );
  }

  /* -------------------- ERROR STATE -------------------- */
  if (error) {
    return (
      <div className="max-w-xl mx-auto mt-20 bg-red-50 dark:bg-red-900/30 text-red-700 dark:text-red-300 p-6 rounded-xl text-center">
        <h2 className="text-lg font-semibold mb-2">Something went wrong</h2>
        <p className="text-sm">{error}</p>
        <p className="mt-3 text-xs opacity-70">
          Try checking the username or platform.
        </p>
      </div>
    );
  }

  /* -------------------- EMPTY DATA STATE -------------------- */
  if (!data.length) {
    return (
      <div className="max-w-xl mx-auto mt-20 text-center text-gray-500 dark:text-gray-400">
        <h2 className="text-xl font-semibold mb-2">
          No growth data found
        </h2>
        <p className="text-sm">
          We’re either fetching data for the first time, or this user has no
          recorded activity yet.
        </p>
      </div>
    );
  }
  

  /* -------------------- SUCCESS STATE -------------------- */
  return (
    <div className="max-w-5xl mx-auto p-6 space-y-6">
      {/* Header card */}
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow p-5">
        <h2 className="text-2xl font-bold">
          {username}
        </h2>
        <p className="text-sm text-gray-500 dark:text-gray-400 capitalize">
          Platform: {platform}
        </p>
      </div>

      {/* Chart card */}
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow p-6">
        <h3 className="text-lg font-semibold mb-4">
          Rating / Score Progress
        </h3>

        <ResponsiveContainer width="100%" height={350}>
          <LineChart data={data}>
            <CartesianGrid
              strokeDasharray="3 3"
              strokeOpacity={0.2}
            />
            <XAxis
              dataKey="date"
              tick={{ fontSize: 12 }}
            />
            <YAxis
              tick={{ fontSize: 12 }}
              allowDecimals={false}
            />
            <Tooltip />
            <Line
              type="monotone"
              dataKey="score"
              stroke="#6366f1"
              strokeWidth={3}
              dot={false}
            />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}
